# Contar total de imagens
TOTAL_IMGS=$(python3 -c "
import json
d=json.load(open('/tmp/trc_projects.json'))
total=0
for p in d:
    # thumb pode já estar nos imgs, mas vamos contá-lo separadamente se não estiver
    urls = set([i['url'] for i in p['imgs']])
    if p['thumb'] not in urls:
        urls.add(p['thumb'])
    total += len(urls)
print(total)
")
echo "Total de imagens únicas a descarregar: $TOTAL_IMGS"
